class Solution:
    def constructMaximumBinaryTree(self, nums):
        def build(lo, hi):
            if lo > hi:
                return None
            mi = lo
            for i in range(lo + 1, hi + 1):
                if nums[i] > nums[mi]:
                    mi = i
            node = TreeNode(nums[mi])
            node.left = build(lo, mi - 1)
            node.right = build(mi + 1, hi)
            return node
        return build(0, len(nums) - 1)

